#include <iostream>
#include <string>
using namespace std;

class BankAccount {
// === ЗАКРИТО ДЛЯ ВСІХ ЗОВНІ ===
private:
    string owner;
    double balance;

    // Внутрішній метод. Його НЕ можна викликати з main(). Тільки інші методи класу!
    void triggerAlarm() {
        cout << "[ТРИВОГА] Зафіксована спроба хакерства на рахунку " << owner << "!" << endl;
    }

// === ВІДКРИТО ДЛЯ ВЗАЄМОДІЇ ===
public:
    // Конструктор
    BankAccount(string o, double b) : owner(o), balance(b) {}

    // GETTER - (видача даних безпечно)
    double getBalance() { 
        return balance; 
    }
    string getOwner() { 
        return owner; 
    }

    // SETTER (модифікація даних з жорсткою ПЕРЕВІРКОЮ)
    void deposit(double amount) {
        if (amount <= 0) { 
            cout << "Помилка. Сума поповнення має бути > 0." << endl; 
            return; 
        }
        balance += amount; // Лише тут змінюємо приватну змінну
        cout << owner << " поповнив на: $" << amount << endl;
    }

    // Ще один логічний метод (Зняття)
    bool withdraw(double amount) {
        // Захист від балансу в мінус!
        // Гроші за стіною `private` у 100% безпеці.
        if (amount > balance) { 
            cout << "Недостатньо коштів для " << owner << "!" << endl; 
            triggerAlarm(); // Виклик приватної функції!
            return false; 
        }
        balance -= amount;
        cout << owner << " зняв: $" << amount << " | Залишок: $" << balance << endl;
        return true;
    }
};

int main() {
    BankAccount acc("Olena", 5000);

    // ПОМИЛКА! Не можна ззовні змінити:
    // acc.balance = 999999; // Компілятор видасть ERROR: 'balance' is a private member

    // АЛЕ можна безпечно взаємодіяти через інтерфейс:
    cout << "Баланс рахунку: " << acc.getBalance() << endl; // Читання

    acc.deposit(1000);
    acc.withdraw(8000); // 8000 > 6000, спрацює захист та тривога!
    acc.withdraw(500);  // Це пройде

    return 0;
}
